129	        final ExecutorService loaderExecutor = Executors.newFixedThreadPool(matchingEnginesNum + riskEnginesNum, threadFactory);
130	
131	        // start creating matching engines
132	        final Map<Integer, CompletableFuture<MatchingEngineRouter>> matchingEngineFutures = IntStream.range(0, matchingEnginesNum)
133	                .boxed()
134	                .collect(Collectors.toMap(
135	                        shardId -> shardId,
136	                        shardId -> CompletableFuture.supplyAsync(
137	                                () -> new MatchingEngineRouter(shardId, matchingEnginesNum, serializationProcessor, orderBookFactory, sharedPool, exchangeConfiguration),
138	                                loaderExecutor)));
139	
140	        // TODO create processors in same thread we will execute it??
141	
142	        // start creating risk engines
143	        final Map<Integer, CompletableFuture<RiskEngine>> riskEngineFutures = IntStream.range(0, riskEnginesNum)
144	                .boxed()
145	                .collect(Collectors.toMap(
146	                        shardId -> shardId,
147	                        shardId -> CompletableFuture.supplyAsync(
148	                                () -> new RiskEngine(shardId, riskEnginesNum, serializationProcessor, sharedPool, exchangeConfiguration),
149	                                loaderExecutor)));
150	
151	        final EventHandler<OrderCommand>[] matchingEngineHandlers = matchingEngineFutures.values().stream()
152	                .map(CompletableFuture::join)
153	                .map(mer -> (EventHandler<OrderCommand>) (cmd, seq, eob) -> mer.processOrder(seq, cmd))
154	                .toArray(ExchangeCore::newEventHandlersArray);
155	
156	        final Map<Integer, RiskEngine> riskEngines = riskEngineFutures.entrySet().stream()
157	                .collect(Collectors.toMap(
158	                        Map.Entry::getKey,
159	                        entry -> entry.getValue().join()));
160	
161	
162	        final List<TwoStepMasterProcessor> procR1 = new ArrayList<>(riskEnginesNum);
163	        final List<TwoStepSlaveProcessor> procR2 = new ArrayList<>(riskEnginesNum);
164	
165	        // 1. grouping processor (G)
166	        final EventHandlerGroup<OrderCommand> afterGrouping =
167	                disruptor.handleEventsWith((rb, bs) -> new GroupingProcessor(rb, rb.newBarrier(bs), perfCfg, coreWaitStrategy, sharedPool));
168	
169	        // 2. [journaling (J)] in parallel with risk hold (R1) + matching engine (ME)
170	
171	        boolean enableJournaling = serializationCfg.isEnableJournaling();
172	        final EventHandler<OrderCommand> jh = enableJournaling ? serializationProcessor::writeToJournal : null;
173	
174	        if (enableJournaling) {
175	            afterGrouping.handleEventsWith(jh);
176	        }
177	
178	        riskEngines.forEach((idx, riskEngine) -> afterGrouping.handleEventsWith(
179	                (rb, bs) -> {
180	                    final TwoStepMasterProcessor r1 = new TwoStepMasterProcessor(rb, rb.newBarrier(bs), riskEngine::preProcessCommand, exceptionHandler, coreWaitStrategy, "R1_" + idx);
181	                    procR1.add(r1);
182	                    return r1;
183	                }));
184	
185	        disruptor.after(procR1.toArray(new TwoStepMasterProcessor[0])).handleEventsWith(matchingEngineHandlers);
186	
187	        // 3. risk release (R2) after matching engine (ME)
188	        final EventHandlerGroup<OrderCommand> afterMatchingEngine = disruptor.after(matchingEngineHandlers);
189	
190	        riskEngines.forEach((idx, riskEngine) -> afterMatchingEngine.handleEventsWith(
191	                (rb, bs) -> {
