202	
203	        final ResultsHandler resultsHandler = new ResultsHandler(resultsConsumer);
204	
205	        mainHandlerGroup.handleEventsWith((cmd, seq, eob) -> {
206	            resultsHandler.onEvent(cmd, seq, eob);
