208	        });
209	
210	        // attach slave processors to master processor
211	        IntStream.range(0, riskEnginesNum).forEach(i -> procR1.get(i).setSlaveProcessor(procR2.get(i)));
212	
213	        try {
214	            loaderExecutor.shutdown();
215	            loaderExecutor.awaitTermination(1, TimeUnit.SECONDS);
216	        } catch (InterruptedException ex) {
217	            throw new RuntimeException(ex);
218	        }
219	    }
