41	
42	    public TwoStepSlaveProcessor(final RingBuffer<OrderCommand> ringBuffer,
43	                                 final SequenceBarrier sequenceBarrier,
44	                                 final SimpleEventHandler eventHandler,
45	                                 final ExceptionHandler<? super OrderCommand> exceptionHandler,
46	                                 final String name) {
