56	    public Sequence getSequence() {
57	        return sequence;
58	    }
59	
60	    @Override
61	    public void halt() {
62	        running.set(HALTED);
63	        sequenceBarrier.alert();
64	    }
65	
66	    @Override
67	    public boolean isRunning() {
68	        return running.get() != IDLE;
69	    }
70	
